mapper.sql:
b.store_id = #{store_id}
and a.recycle=0
and b.id = a.pid
and b.active = #{active}
and b.is_presell = #{is_presell}
and b.status = #{goodsStatus}
and b.mch_status = #{mch_status}
and a.num  >  #{stockNum_gt}
and a.num = #{stockNum}
and a.id = #{attr_id}
and b.id = #{goodsId}
and b.status = #{goodsStatus}
