and b.product_class like concat('%-',#{product_class},'-%')
and b.brand_id = #{brand_id}
and b.mch_id = #{mchId}
AND b.product_class LIKE CONCAT('%-', #{cid},'-%')
and b.commodity_type = #{commodity_type}
and b.product_title like concat('%',#{product_title},'%')
and a.id not in (SELECT attr_id from lkt_seconds_pro where store_id = #{store_id}
    and is_delete = 0 and label_id = #{label_id})

 and (b.gongyingshang is null or b.gongyingshang = '')

mapper.select:
select a.id as attr_id, b.id goodsId, b.product_title,a.img imgurl,c.id mch_id,c.name,a.num,a.total_num,b.min_inventory,a.attribute,a.price as price,b.product_number from lkt_configure as a left join lkt_product_list as b on a.pid = b.id left join lkt_mch as c on b.mch_id = c.id
a.price ${price_sort},
LIMIT #{pageStart},#{pageEnd}

mapper.sql:
and a.recycle = 0 and c.recycle = 0 and a.mch_status = 2
and c.num  <=  a.min_inventory
and a.store_id = #{store_id}
and a.mch_id = #{mch_id}
and c.pid = #{pid}
and b.type = #{stockType}
and a.product_title like concat('%',#{goodsName},'%')
and b.startDate  >=  #{startDate}
and b.endDate  <=  #{endDate}

mapper.select:
SELECT ( a.id ), b.id product_number, b.product_title, a.img, a.total_num, s.add_date warnDate, a.num, a.attribute FROM lkt_configure a LEFT JOIN lkt_product_list b ON a.pid = b.id INNER JOIN lkt_stock s ON a.id = s.attribute_id and a.pid = product_id
b.store_id = #{storeId} AND s.type = 2 AND s.add_date >= #{date} AND a.recycle = 0 AND b.recycle = 0
order by a.num asc limit #{pageStart},#{pageEnd}
